export interface Env {
  SENDGRID_API_KEY: string;
  SENDGRID_FROM_EMAIL: string;
  STRIPE_SECRET_KEY: string;
  API_TOKEN: string;
  ALLOWED_ORIGINS?: string;
}

type Json = Record<string, unknown>;

class HttpError extends Error {
  status: number;
  details?: unknown;

  constructor(status: number, message: string, details?: unknown) {
    super(message);
    this.status = status;
    this.details = details;
  }
}

function jsonResponse(data: unknown, status = 200, headers: HeadersInit = {}) {
  return new Response(JSON.stringify(data), {
    status,
    headers: {
      "content-type": "application/json; charset=utf-8",
      ...headers,
    },
  });
}

function getCorsHeaders(origin: string | null, env: Env): HeadersInit {
  const allowed = (env.ALLOWED_ORIGINS || "*")
    .split(",")
    .map((s) => s.trim())
    .filter(Boolean);

  const allowOrigin =
    allowed.includes("*") || (origin && allowed.includes(origin)) ? origin || "*" : "null";

  return {
    "access-control-allow-origin": allowOrigin,
    "access-control-allow-methods": "GET,POST,OPTIONS",
    "access-control-allow-headers": "content-type,authorization",
    "access-control-max-age": "86400",
    vary: "Origin",
  };
}

function requireAuth(request: Request, env: Env) {
  const auth = request.headers.get("authorization");
  if (!auth || !auth.startsWith("Bearer ")) {
    throw new HttpError(401, "Missing or invalid Authorization header");
  }
  const token = auth.slice("Bearer ".length).trim();
  if (!token || token !== env.API_TOKEN) {
    throw new HttpError(401, "Unauthorized");
  }
}

async function parseJson<T = Json>(request: Request): Promise<T> {
  const contentType = request.headers.get("content-type") || "";
  if (!contentType.includes("application/json")) {
    throw new HttpError(415, "Content-Type must be application/json");
  }
  try {
    return (await request.json()) as T;
  } catch {
    throw new HttpError(400, "Invalid JSON body");
  }
}

function isValidEmail(email: string) {
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
}

async function sendEmail(env: Env, payload: { to: string; subject: string; text?: string; html?: string }) {
  if (!env.SENDGRID_API_KEY) throw new HttpError(500, "Missing SENDGRID_API_KEY");
  if (!env.SENDGRID_FROM_EMAIL) throw new HttpError(500, "Missing SENDGRID_FROM_EMAIL");

  const { to, subject, text, html } = payload;

  if (!to || !isValidEmail(to)) throw new HttpError(400, "Invalid recipient email");
  if (!subject) throw new HttpError(400, "Subject is required");
  if (!text && !html) throw new HttpError(400, "Either text or html content is required");

  const body = {
    personalizations: [{ to: [{ email: to }] }],
    from: { email: env.SENDGRID_FROM_EMAIL },
    subject,
    content: [
      ...(text ? [{ type: "text/plain", value: text }] : []),
      ...(html ? [{ type: "text/html", value: html }] : []),
    ],
  };

  const res = await fetch("https://api.sendgrid.com/v3/mail/send", {
    method: "POST",
    headers: {
      authorization: `Bearer ${env.SENDGRID_API_KEY}`,
      "content-type": "application/json",
    },
    body: JSON.stringify(body),
  });

  if (!res.ok) {
    let details: unknown;
    try {
      details = await res.json();
    } catch {
      details = await res.text();
    }
    throw new HttpError(502, "SendGrid API error", {
      provider: "sendgrid",
      status: res.status,
      details,
    });
  }

  return { success: true, provider: "sendgrid" };
}

function toStripeForm(data: Record<string, string | number | boolean | undefined | null>) {
  const params = new URLSearchParams();
  for (const [key, value] of Object.entries(data)) {
    if (value !== undefined && value !== null) {
      params.append(key, String(value));
    }
  }
  return params.toString();
}

async function createPaymentIntent(env: Env, payload: { amount: number; currency: string; description?: string; receipt_email?: string }) {
  if (!env.STRIPE_SECRET_KEY) throw new HttpError(500, "Missing STRIPE_SECRET_KEY");

  const { amount, currency, description, receipt_email } = payload;

  if (!Number.isInteger(amount) || amount <= 0) {
    throw new HttpError(400, "Amount must be a positive integer in the smallest currency unit");
  }
  if (!currency || !/^[a-z]{3}$/.test(currency)) {
    throw new HttpError(400, "Currency must be a 3-letter lowercase ISO code");
  }
  if (receipt_email && !isValidEmail(receipt_email)) {
    throw new HttpError(400, "Invalid receipt_email");
  }

  const body = toStripeForm({
    amount,
    currency,
    description,
    receipt_email,
    "automatic_payment_methods[enabled]": true,
  });

  const res = await fetch("https://api.stripe.com/v1/payment_intents", {
    method: "POST",
    headers: {
      authorization: `Bearer ${env.STRIPE_SECRET_KEY}`,
      "content-type": "application/x-www-form-urlencoded",
    },
    body,
  });

  let data: any;
  try {
    data = await res.json();
  } catch {
    throw new HttpError(502, "Invalid response from Stripe");
  }

  if (!res.ok) {
    throw new HttpError(502, "Stripe API error", {
      provider: "stripe",
      status: res.status,
      details: data,
    });
  }

  return {
    success: true,
    provider: "stripe",
    payment_intent: {
      id: data.id,
      client_secret: data.client_secret,
      amount: data.amount,
      currency: data.currency,
      status: data.status,
    },
  };
}

async function handleRequest(request: Request, env: Env): Promise<Response> {
  const url = new URL(request.url);
  const origin = request.headers.get("origin");
  const corsHeaders = getCorsHeaders(origin, env);

  if (request.method === "OPTIONS") {
    return new Response(null, { status: 204, headers: corsHeaders });
  }

  if (url.pathname === "/health" && request.method === "GET") {
    return jsonResponse(
      { ok: true, service: "worker", timestamp: new Date().toISOString() },
      200,
      corsHeaders
    );
  }

  requireAuth(request, env);

  if (url.pathname === "/email/send" && request.method === "POST") {
    const body = await parseJson<{ to: string; subject: string; text?: string; html?: string }>(request);
    const result = await sendEmail(env, body);
    return jsonResponse(result, 200, corsHeaders);
  }

  if (url.pathname === "/payments/create-intent" && request.method === "POST") {
    const body = await parseJson<{ amount: number; currency: string; description?: string; receipt_email?: string }>(request);
    const result = await createPaymentIntent(env, body);
    return jsonResponse(result, 200, corsHeaders);
  }

  throw new HttpError(404, "Not Found");
}

export default {
  async fetch(request: Request, env: Env): Promise<Response> {
    const origin = request.headers.get("origin");
    const corsHeaders = getCorsHeaders(origin, env);

    try {
      return await handleRequest(request, env);
    } catch (err: any) {
      if (err instanceof HttpError) {
        return jsonResponse(
          {
            error: err.message,
            ...(err.details !== undefined ? { details: err.details } : {}),
          },
          err.status,
          corsHeaders
        );
      }

      return jsonResponse(
        {
          error: "Internal Server Error",
        },
        500,
        corsHeaders
      );
    }
  },
};